class BiometricService {
  final LocalAuthentication _localAuth = LocalAuthentication();

  Future<BiometricStatus> checkBiometricAvailability() async {
    try {
      final canCheckBiometrics = await _localAuth.canCheckBiometrics;
      final isDeviceSupported = await _localAuth.isDeviceSupported();

      if (!canCheckBiometrics || !isDeviceSupported) {
        return BiometricStatus.unavailable;
      }

      final availableBiometrics = await _localAuth.getAvailableBiometrics();

      if (availableBiometrics.isEmpty) {
        return BiometricStatus.notEnrolled;
      }

      if (availableBiometrics.contains(BiometricType.face)) {
        return BiometricStatus.faceAvailable;
      }

      if (availableBiometrics.contains(BiometricType.fingerprint) ||
          availableBiometrics.contains(BiometricType.strong)) {
        return BiometricStatus.fingerprintAvailable;
      }

      return BiometricStatus.available;
    } on PlatformException {
      return BiometricStatus.unavailable;
    }
  }

  /// Perform biometric authentication
  /// Returns true only if the OS-level biometric check succeeds
  Future<bool> authenticate({String reason = 'Verify your identity'}) async {
    try {
      return await _localAuth.authenticate(
        localizedReason: reason,
        options: const AuthenticationOptions(
          stickyAuth: true,
          biometricOnly: false, // Allow device PIN as biometric fallback
          useErrorDialogs: true,
        ),
      );
    } on PlatformException catch (e) {
      debugPrint('Biometric auth error: ${e.code} - ${e.message}');
      return false;
    }
  }
}

enum BiometricStatus {
  available,
  faceAvailable,
  fingerprintAvailable,
  notEnrolled,
  unavailable,
}

